216	// mustAP parses a single "ip:port" endpoint or fails the test.
217	func mustAP(t *testing.T, s string) netip.AddrPort {
218		t.Helper()
219		ap, err := netip.ParseAddrPort(s)
220		if err != nil {
221			t.Fatalf("parse endpoint %q: %v", s, err)
222		}
223		return ap
224	}
