240	// TestHubFailoverStandbyRecordSwapNoRepoint is acceptance (1): swapping a STANDBY spec's
241	// expansion (a hostname re-resolving off the active spec) must NOT touch the bond — zero
242	// SetPeerRemote, zero re-handshake — and must leave the active pointer on its own entry.
243	func TestHubFailoverStandbyRecordSwapNoRepoint(t *testing.T) {
244		active := mustAP(t, "203.0.113.1:51820")
245		specs := []failoverSpec{
246			litSpec(t, "203.0.113.1:51820"),                                         // spec 0: active literal
247			nameSpec("standby.example.com", 51820, mustAP(t, "198.51.100.7:51820")), // spec 1: standby hostname
248		}
249		hp := []hubHealth{&fakeHealth{telemetry.StateUp}, &fakeHealth{telemetry.StateUp}}
250		rem := &recordingRemote{}
251		handshakes := 0
252		clk := &fakeClock{now: time.Unix(1000, 0)}
253		h := newHubFailoverFromSpecs(specs, hp, rem, func() { handshakes++ }, clk, testSettle, discardLogger(t))
254		if h.activeSpec != 0 || h.activeAddr != active {
255			t.Fatalf("boot active = (%d,%v), want (0,%v)", h.activeSpec, h.activeAddr, active)
256		}
257	
258		// The standby hostname re-resolves onto a DIFFERENT record.
259		h.updateResolution(1, []netip.AddrPort{mustAP(t, "192.0.2.9:51820")})
260	
261		if rem.calls != 0 || handshakes != 0 {
262			t.Fatalf("standby-record swap touched the bond: SetPeerRemote=%d handshakes=%d, want 0,0", rem.calls, handshakes)
263		}
264		if h.activeSpec != 0 || h.activeAddr != active {
265			t.Fatalf("standby-record swap moved the active pointer to (%d,%v), want (0,%v)", h.activeSpec, h.activeAddr, active)
266		}
267		if h.idx != 0 {
268			t.Fatalf("active flattened idx = %d, want 0 (unchanged; the standby follows the active spec)", h.idx)
269		}
270	}
271	
272	// TestHubFailoverActiveIPChangeRepointsOnce is acceptance (2): when the ACTIVE spec (a
273	// hostname) re-resolves off its current AddrPort, the active endpoint's IP has changed, so
274	// the bond is repointed via EXACTLY one SetPeerRemote + one re-handshake to the new record.
275	func TestHubFailoverActiveIPChangeRepointsOnce(t *testing.T) {
276		oldA := mustAP(t, "203.0.113.1:51820")
277		newA := mustAP(t, "203.0.113.2:51820")
278		specs := []failoverSpec{
279			nameSpec("hub.example.com", 51820, oldA), // spec 0: active hostname
280			litSpec(t, "198.51.100.7:51820"),         // spec 1: literal standby
281		}
282		hp := []hubHealth{&fakeHealth{telemetry.StateUp}}
283		rem := &recordingRemote{}
284		handshakes := 0
285		clk := &fakeClock{now: time.Unix(1000, 0)}
286		h := newHubFailoverFromSpecs(specs, hp, rem, func() { handshakes++ }, clk, testSettle, discardLogger(t))
287		if h.activeSpec != 0 || h.activeAddr != oldA {
288			t.Fatalf("boot active = (%d,%v), want (0,%v)", h.activeSpec, h.activeAddr, oldA)
289		}
290	
291		h.updateResolution(0, []netip.AddrPort{newA})
292	
293		if rem.calls != 1 {
294			t.Fatalf("active-IP change SetPeerRemote=%d, want exactly 1", rem.calls)
295		}
296		if rem.last != newA {
297			t.Fatalf("repointed remote = %v, want new active record %v", rem.last, newA)
298		}
299		if handshakes != 1 {
300			t.Fatalf("active-IP change re-handshakes=%d, want exactly 1", handshakes)
301		}
302		if h.activeSpec != 0 || h.activeAddr != newA {
303			t.Fatalf("active pointer = (%d,%v), want (0,%v)", h.activeSpec, h.activeAddr, newA)
304		}
305	}
306	
307	// TestHubFailoverUnchangedActiveIPNoRepoint is acceptance (3): re-resolving the ACTIVE spec
308	// onto a record set that STILL contains the current active AddrPort is a no-op for the bond
309	// (Q31/D32 suppression) — zero SetPeerRemote, zero re-handshake.
310	func TestHubFailoverUnchangedActiveIPNoRepoint(t *testing.T) {
311		active := mustAP(t, "203.0.113.1:51820")
312		extra := mustAP(t, "203.0.113.9:51820")
313		specs := []failoverSpec{
314			nameSpec("hub.example.com", 51820, active), // spec 0: active hostname
315			litSpec(t, "198.51.100.7:51820"),           // spec 1: literal standby
316		}
317		hp := []hubHealth{&fakeHealth{telemetry.StateUp}}
318		rem := &recordingRemote{}
319		handshakes := 0
320		clk := &fakeClock{now: time.Unix(1000, 0)}
321		h := newHubFailoverFromSpecs(specs, hp, rem, func() { handshakes++ }, clk, testSettle, discardLogger(t))
322	
323		// Re-resolve: the record set changed (grew) but STILL contains the active AddrPort.
324		h.updateResolution(0, []netip.AddrPort{active, extra})
325	
326		if rem.calls != 0 || handshakes != 0 {
327			t.Fatalf("unchanged active IP touched the bond: SetPeerRemote=%d handshakes=%d, want 0,0", rem.calls, handshakes)
328		}
329		if h.activeSpec != 0 || h.activeAddr != active {
330			t.Fatalf("active pointer = (%d,%v), want (0,%v) (survived the swap)", h.activeSpec, h.activeAddr, active)
331		}
332		if h.idx != 0 {
333			t.Fatalf("active flattened idx = %d, want 0", h.idx)
334		}
335	}
336	
337	// TestHubFailoverIdxReMapsOnExpansionGrowShrink is acceptance (4): when a STANDBY spec
338	// ordered BEFORE the active entry grows or shrinks, the active entry's FLATTENED index
339	// re-maps to its new offset — the active identity is spec-scoped, not a frozen flat index —
340	// while the bond is never touched (standby-only change).
341	func TestHubFailoverIdxReMapsOnExpansionGrowShrink(t *testing.T) {
342		activeLit := mustAP(t, "198.51.100.7:51820")
343		specs := []failoverSpec{
344			nameSpec("early.example.com", 51820), // spec 0: hostname, EMPTY at boot
345			litSpec(t, "198.51.100.7:51820"),     // spec 1: literal → boot-active (flat[0])
346		}
347		hp := []hubHealth{&fakeHealth{telemetry.StateUp}}
348		rem := &recordingRemote{}
349		handshakes := 0
350		clk := &fakeClock{now: time.Unix(1000, 0)}
351		h := newHubFailoverFromSpecs(specs, hp, rem, func() { handshakes++ }, clk, testSettle, discardLogger(t))
352		if h.activeSpec != 1 || h.activeAddr != activeLit || h.idx != 0 {
353			t.Fatalf("boot active = (%d,%v) idx=%d, want (1,%v) idx=0", h.activeSpec, h.activeAddr, h.idx, activeLit)
354		}
355	
356		// Grow the earlier standby spec 0 from [] to two records: active flat idx 0 → 2.
357		h.updateResolution(0, []netip.AddrPort{mustAP(t, "203.0.113.1:51820"), mustAP(t, "203.0.113.2:51820")})
358		if rem.calls != 0 || handshakes != 0 {
359			t.Fatalf("growing a standby spec touched the bond: SetPeerRemote=%d handshakes=%d, want 0,0", rem.calls, handshakes)
360		}
361		if h.activeSpec != 1 || h.activeAddr != activeLit || h.idx != 2 {
362			t.Fatalf("after grow: active=(%d,%v) idx=%d, want (1,%v) idx=2", h.activeSpec, h.activeAddr, h.idx, activeLit)
363		}
364	
365		// Shrink the earlier standby spec 0 to one record: active flat idx 2 → 1.
366		h.updateResolution(0, []netip.AddrPort{mustAP(t, "203.0.113.1:51820")})
367		if rem.calls != 0 || handshakes != 0 {
368			t.Fatalf("shrinking a standby spec touched the bond: SetPeerRemote=%d handshakes=%d, want 0,0", rem.calls, handshakes)
369		}
370		if h.activeSpec != 1 || h.activeAddr != activeLit || h.idx != 1 {
371			t.Fatalf("after shrink: active=(%d,%v) idx=%d, want (1,%v) idx=1", h.activeSpec, h.activeAddr, h.idx, activeLit)
372		}
373	}
374	
375	// TestPeerNeedsHubFailover is acceptance (5): a single-IP-literal peer warrants NO
376	// controller (byte-for-byte pre-G5), while a peer with any hostname spec OR >= 2 flattened
377	// literals does. This is the exact construction gate startHubFailover applies per peer.
378	func TestPeerNeedsHubFailover(t *testing.T) {
379		lit := func(s string) config.EndpointSpec { return config.EndpointSpec{Addr: mustAP(t, s)} }
380		name := func(h string, p uint16) config.EndpointSpec {
381			return config.EndpointSpec{Host: h, Port: p, IsName: true}
382		}
383	
384		cases := []struct {
385			name string
386			peer config.Peer
387			want bool
388		}{
389			{
390				name: "single IP literal → no controller",
391				peer: config.Peer{
392					Endpoints:     mustEndpoints(t, "203.0.113.1:51820"),
393					EndpointSpecs: []config.EndpointSpec{lit("203.0.113.1:51820")},
394				},
395				want: false,
396			},
397			{
398				name: "two IP literals → controller",
399				peer: config.Peer{
400					Endpoints:     mustEndpoints(t, "203.0.113.1:51820", "198.51.100.7:51820"),
401					EndpointSpecs: []config.EndpointSpec{lit("203.0.113.1:51820"), lit("198.51.100.7:51820")},
402				},
403				want: true,
404			},
405			{
406				name: "single hostname → controller (may re-resolve onto a new IP)",
407				peer: config.Peer{
408					Endpoints:     nil,
409					EndpointSpecs: []config.EndpointSpec{name("hub.example.com", 51820)},
410				},
411				want: true,
412			},
413			{
414				name: "hostname + literal → controller",
415				peer: config.Peer{
416					Endpoints:     mustEndpoints(t, "203.0.113.1:51820"),
417					EndpointSpecs: []config.EndpointSpec{name("hub.example.com", 51820), lit("203.0.113.1:51820")},
418				},
419				want: true,
420			},
421		}
422		for _, tc := range cases {
423			t.Run(tc.name, func(t *testing.T) {
424				if got := peerNeedsHubFailover(tc.peer); got != tc.want {
425					t.Fatalf("peerNeedsHubFailover = %v, want %v", got, tc.want)
426				}
427			})
428		}
429	}
430	
431	// TestHubFailoverBootAdoptsFirstResolution is acceptance (7): a hostname-only peer boots
432	// with every spec's expansion EMPTY (activeSpec == -1) — check can never rescue it (a
433	// one-record expansion keeps the flattened length at 1, under the total<2 guard), so the
434	// first resolution MUST adopt its head as the active endpoint and point the bond at it via
435	// exactly one SetPeerRemote + one re-handshake, arming the settle dwell.
436	func TestHubFailoverBootAdoptsFirstResolution(t *testing.T) {
437		first := mustAP(t, "203.0.113.1:51820")
438		specs := []failoverSpec{
439			nameSpec("hub.example.com", 51820), // sole spec: hostname, EMPTY at boot
440		}
441		hp := []hubHealth{&fakeHealth{telemetry.StateDown}}
442		rem := &recordingRemote{}
443		handshakes := 0
444		clk := &fakeClock{now: time.Unix(1000, 0)}
445		h := newHubFailoverFromSpecs(specs, hp, rem, func() { handshakes++ }, clk, testSettle, discardLogger(t))
446		if h.activeSpec != -1 || h.idx != -1 {
447			t.Fatalf("boot active = (spec %d, idx %d), want (spec -1, idx -1) (all specs empty)", h.activeSpec, h.idx)
448		}
449	
450		// First resolution populates the sole hostname spec: adopt its head, point the bond.
451		h.updateResolution(0, []netip.AddrPort{first})
452	
453		if rem.calls != 1 || rem.last != first {
454			t.Fatalf("first resolution SetPeerRemote=%d last=%v, want 1 and %v (adopt head)", rem.calls, rem.last, first)
455		}
456		if handshakes != 1 {
457			t.Fatalf("first resolution re-handshakes=%d, want 1", handshakes)
458		}
459		if h.activeSpec != 0 || h.activeAddr != first || h.idx != 0 {
460			t.Fatalf("post-adoption active = (%d,%v) idx=%d, want (0,%v) idx=0", h.activeSpec, h.activeAddr, h.idx, first)
461		}
462		// The dwell is armed at adoption time, not construction time.
463		if !h.lastSwitch.Equal(clk.now) {
464			t.Fatalf("lastSwitch=%v, want %v (armed at adoption)", h.lastSwitch, clk.now)
465		}
466	}
467	
468	// TestHubFailoverRepointResetsSettleDwell is acceptance (8): an active-IP-change repoint
469	// (T73's liveness-loss re-resolution flow) must RE-ARM the settle dwell, so the next
470	// all-down check within the dwell does NOT immediately advance off the just-repointed
471	// endpoint — a second disruptive SetPeerRemote before the new address can prove itself.
472	func TestHubFailoverRepointResetsSettleDwell(t *testing.T) {
473		oldA := mustAP(t, "203.0.113.1:51820")
474		newA := mustAP(t, "203.0.113.2:51820")
475		standby := mustAP(t, "198.51.100.7:51820")
476		specs := []failoverSpec{
477			nameSpec("hub.example.com", 51820, oldA), // spec 0: active hostname
478			litSpec(t, "198.51.100.7:51820"),         // spec 1: literal standby
479		}
480		hp := []hubHealth{&fakeHealth{telemetry.StateDown}, &fakeHealth{telemetry.StateDown}}
481		rem := &recordingRemote{}
482		handshakes := 0
483		clk := &fakeClock{now: time.Unix(1000, 0)}
484		h := newHubFailoverFromSpecs(specs, hp, rem, func() { handshakes++ }, clk, testSettle, discardLogger(t))
485	
486		// Let the boot dwell fully elapse so, absent a reset, the next all-down check WOULD advance.
487		clk.advance(testSettle + time.Second)
488	
489		// The active spec re-resolves to a new IP under hub loss: repoint (one switch).
490		h.updateResolution(0, []netip.AddrPort{newA})
491		if rem.calls != 1 || rem.last != newA {
492			t.Fatalf("repoint SetPeerRemote=%d last=%v, want 1 and %v", rem.calls, rem.last, newA)
493		}
494	
495		// The repoint re-armed the dwell: a check WITHIN the settle must NOT advance off the
496		// just-repointed endpoint, even though every path still reads DOWN.
497		clk.advance(testSettle - time.Millisecond)
498		h.check()
499		if rem.calls != 1 {
500			t.Fatalf("advanced within the dwell after a repoint: SetPeerRemote=%d, want 1 (no second switch)", rem.calls)
501		}
502		if h.activeSpec != 0 || h.activeAddr != newA {
503			t.Fatalf("active moved off the repointed endpoint within the dwell: (%d,%v), want (0,%v)", h.activeSpec, h.activeAddr, newA)
504		}
505	
506		// Once the dwell elapses relative to the repoint, the controller may advance (to standby).
507		clk.advance(2 * time.Millisecond)
508		h.check()
509		if rem.calls != 2 || rem.last != standby {
510			t.Fatalf("no advance after the dwell elapsed: SetPeerRemote=%d last=%v, want 2 and %v", rem.calls, rem.last, standby)
511		}
512	}
513	
514	// TestHubFailoverCrossSpecDuplicateNoSpuriousReMap is acceptance (6), the R70 case: a
515	// hostname STANDBY spec re-resolving onto the SAME AddrPort as the active spec's own literal
516	// must NOT move the active pointer (spec-scoped identity, not bare value) and must not touch
517	// the bond; a subsequent hub-loss advance then walks the FLATTENED order correctly past the
518	// duplicate rather than being confused by it.
519	func TestHubFailoverCrossSpecDuplicateNoSpuriousReMap(t *testing.T) {
520		dup := mustAP(t, "203.0.113.1:51820")   // shared AddrPort across specs 0 and 1
521		tail := mustAP(t, "198.51.100.7:51820") // spec 2 literal standby
522		specs := []failoverSpec{
523			nameSpec("shadow.example.com", 51820), // spec 0: hostname, EMPTY at boot
524			litSpec(t, "203.0.113.1:51820"),       // spec 1: literal dup → boot-active (flat[0])
525			litSpec(t, "198.51.100.7:51820"),      // spec 2: literal standby
526		}
527		hp := []hubHealth{&fakeHealth{telemetry.StateDown}, &fakeHealth{telemetry.StateDown}}
528		rem := &recordingRemote{}
529		handshakes := 0
530		clk := &fakeClock{now: time.Unix(1000, 0)}
531		h := newHubFailoverFromSpecs(specs, hp, rem, func() { handshakes++ }, clk, testSettle, discardLogger(t))
532		if h.activeSpec != 1 || h.activeAddr != dup || h.idx != 0 {
533			t.Fatalf("boot active = (%d,%v) idx=%d, want (1,%v) idx=0", h.activeSpec, h.activeAddr, h.idx, dup)
534		}
535	
536		// The standby hostname (spec 0) re-resolves onto the SAME AddrPort as the active spec-1
537		// literal. A bare-value re-map would rebind the active pointer to spec 0's duplicate at
538		// flat index 0; the spec-scoped identity must keep it on spec 1 (now at flat index 1).
539		h.updateResolution(0, []netip.AddrPort{dup})
540		if rem.calls != 0 || handshakes != 0 {
541			t.Fatalf("cross-spec duplicate re-resolution touched the bond: SetPeerRemote=%d handshakes=%d, want 0,0", rem.calls, handshakes)
542		}
543		if h.activeSpec != 1 || h.activeAddr != dup {
544			t.Fatalf("active pointer spuriously re-mapped to (%d,%v), want (1,%v) (own spec's entry)", h.activeSpec, h.activeAddr, dup)
545		}
546		if h.idx != 1 {
547			t.Fatalf("active flattened idx = %d, want 1 (spec-1 dup, past spec-0's duplicate at 0)", h.idx)
548		}
549	
550		// A subsequent hub-loss advance must walk the flattened order to spec 2's tail literal
551		// at flat index 2 — NOT stall on the duplicate at index 0/1.
552		clk.advance(testSettle + time.Second)
553		h.check()
554		if rem.calls != 1 || rem.last != tail {
555			t.Fatalf("advance after duplicate: SetPeerRemote=%d last=%v, want 1 and %v (flattened order to spec-2 tail)", rem.calls, rem.last, tail)
556		}
557		if h.activeSpec != 2 || h.activeAddr != tail || h.idx != 2 {
558			t.Fatalf("post-advance active = (%d,%v) idx=%d, want (2,%v) idx=2", h.activeSpec, h.activeAddr, h.idx, tail)
559		}
560		if handshakes != 1 {
561			t.Fatalf("advance re-handshakes=%d, want 1", handshakes)
562		}
563	}
564

