	// initial scheduled poll (unchanged IP → no repoint).
	h.advancePastPoll()
	h.res.step()
	if h.rem.calls != 0 {
		t.Fatalf("baseline step repointed %d times, want 0", h.rem.calls)
	}
	callsBefore := h.rslv.callCount()

