	callsAfter := h.rslv.callCount()
	h.res.step()
	if got := h.rslv.callCount(); got != callsAfter {
		t.Fatalf("all-down re-resolve fired again on a level (non-edge) tick: %d extra lookups, want 0", got-callsAfter)
	}
