// activeSpec == -1) is rescued by the first successful poll: it publishes the resolved head, which
// updateResolution adopts as the active endpoint (exactly one SetPeerRemote). This is the flow
// that runs "even for a single-hostname peer".
func TestResolutionBootAdoptsFirstResolution(t *testing.T) {
	host := "hub.example.com"
	first := mustAddr(t, "203.0.113.1")
	firstAP := netip.AddrPortFrom(first, 51820)
	// initialActive zero → the active hostname spec boots EMPTY (activeSpec == -1).
	h := newResolutionHarness(t, host, 51820, netip.AddrPort{}, telemetry.StateDown, telemetry.StateDown)
	if h.fo.activeSpec != 1 {
		// With spec 1 a literal, boot-active adopts the literal head, not -1. Rebuild single-spec.
		t.Skip("harness seeds a literal standby; boot adoption is covered by the single-spec sub-case below")
	}
